## ----echo=TRUE----------------------------------------------------------------
taxus_bin_wmt <- taxus_bin[rowSums(taxus_bin) > 1, ]


## ----echo=TRUE----------------------------------------------------------------
set.seed(1)
result_sa <- optim_tdv_simul_anne(
 m_bin = taxus_bin_wmt,
 k = 3,
 p_initial = "random",
 n_runs = 5,
 n_sol = 5,
 use_grasp = FALSE,
 full_output = TRUE
 )


## ----echo=TRUE----------------------------------------------------------------
sapply(result_sa$SANN, function(x) x$tdv)


## ----echo=TRUE----------------------------------------------------------------
result_sa$SANN[[2]]$par


## ----figsannconvergence, fig.asp = 1, out.width = '60%', fig.cap = "Plots of the TDV obtained in each of the five runs of the simulated annealing optimization.", fig.alt= "Plot with TDV in the vertical axis and iteration number in the horizontal axis. Five lines depict the variation in TDV for each run, showing an increase from arround 0.05 in iteration 1 to arround 0.17 to 0.20 in iteration 650 to 850, where they plateau until iteration 1000.", fig.align='center', echo=TRUE----
plot(
 result_sa$SANN[[1]]$current.tdv,
 type = "l",
 xlab = "Iteration number",
 ylab = "TDV"
 )
for (run in 2:5) {
 lines(result_sa$SANN[[run]]$current.tdv)
 }


